#include <stdio.h>
#include <math.h>
#define MAXN 2000
#define MAXVAL 1000000
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int X[MAXN], Y[MAXN];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &X[i], &Y[i]);
        }
        int ans = 4;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                double dist = sqrt((X[i] - X[j]) * (X[i] - X[j]) + (Y[i] - Y[j]) * (Y[i] - Y[j]));
                for (int k = 0; k < N; k++) {
                    for (int l = k + 1; l < N; l++) {
                        double dist2 = sqrt((X[k] - X[l]) * (X[k] - X[l]) + (Y[k] - Y[l]) * (Y[k] - Y[l]));
                        if (dist == dist2) {
                            double dx1 = X[j] - X[i];
                            double dy1 = Y[j] - Y[i];
                            double dx2 = X[l] - X[k];
                            double dy2 = Y[l] - Y[k];
                            if (dx1 * dx2 + dy1 * dy2 == 0) {
                                ans = 0;
                                goto end;
                            }
                        }
                    }
                }
            }
        }
        end:
        printf("%d\n", ans);
    }
    return 0;
}

